"use client";

import { getAssetPath } from './utils';
import { useRef, useEffect, useState, useCallback } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import YearbookViewport from "./YearbookViewport";

gsap.registerPlugin(ScrollTrigger);

/* ─────────────────────────────────────────────────────────────
   Stinger wipe bars
───────────────────────────────────────────────────────────── */
function StingerBars({
  stingerRef1,
  stingerRef2,
  stingerRef3,
}: {
  stingerRef1: React.RefObject<HTMLDivElement | null>;
  stingerRef2: React.RefObject<HTMLDivElement | null>;
  stingerRef3: React.RefObject<HTMLDivElement | null>;
}) {
  return (
    <>
      <div ref={stingerRef1} className="yearbook-stinger yearbook-stinger--1" aria-hidden="true" />
      <div ref={stingerRef2} className="yearbook-stinger yearbook-stinger--2" aria-hidden="true" />
      <div ref={stingerRef3} className="yearbook-stinger yearbook-stinger--3" aria-hidden="true" />
    </>
  );
}

/* ─────────────────────────────────────────────────────────────
   YearbookSection
───────────────────────────────────────────────────────────── */
export default function YearbookSection() {
  const sectionRef = useRef<HTMLElement>(null);
  const textRef    = useRef<HTMLDivElement>(null);
  const ctaRef     = useRef<HTMLDivElement>(null);
  const btnRef     = useRef<HTMLButtonElement>(null);

  // Stinger bars
  const stinger1 = useRef<HTMLDivElement>(null);
  const stinger2 = useRef<HTMLDivElement>(null);
  const stinger3 = useRef<HTMLDivElement>(null);

  const [viewportOpen, setViewportOpen] = useState(false);
  const [stingerDone, setStingerDone]   = useState(false);

  /* ── Scroll-triggered entrance animations ── */
  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.from(textRef.current?.children ?? [], {
        y: 60,
        opacity: 0,
        duration: 1.2,
        stagger: 0.15,
        ease: "power4.out",
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top 75%",
          once: true,
        },
      });

      gsap.from(ctaRef.current, {
        x: 40,
        opacity: 0,
        duration: 1,
        ease: "power3.out",
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top 65%",
          once: true,
        },
      });

      // CTA button pulse-glow idle animation
      if (btnRef.current) {
        gsap.to(btnRef.current, {
          boxShadow: "0 0 30px rgba(110,0,255,0.55), 0 0 60px rgba(110,0,255,0.25)",
          duration: 1.6,
          repeat: -1,
          yoyo: true,
          ease: "sine.inOut",
        });
      }
    });
    return () => ctx.revert();
  }, []);

  /* ── Stinger animation → open viewport ── */
  const openViewport = useCallback(() => {
    const bars = [stinger1.current, stinger2.current, stinger3.current];
    if (!bars[0]) return;

    // Reset
    gsap.set(bars, { scaleY: 0, transformOrigin: "bottom center" });

    const tl = gsap.timeline({
      onComplete: () => {
        setStingerDone(true);
        setViewportOpen(true);
      },
    });

    // Bars wipe UP (staggered)
    tl.to(bars, {
      scaleY: 1,
      duration: 0.38,
      stagger: 0.08,
      ease: "power4.in",
    })
    // Hold for one frame at full wipe, then collapse from top
    .to(bars, {
      scaleY: 0,
      transformOrigin: "top center",
      duration: 0.32,
      stagger: 0.06,
      ease: "power4.out",
      delay: 0.05,
    });
  }, []);

  /* ── Stinger out-wipe → close viewport ── */
  const closeViewport = useCallback(() => {
    const bars = [stinger1.current, stinger2.current, stinger3.current];

    if (!bars[0]) {
      setViewportOpen(false);
      setStingerDone(false);
      return;
    }

    gsap.set(bars, { scaleY: 0, transformOrigin: "top center" });

    const tl = gsap.timeline({
      onComplete: () => {
        setViewportOpen(false);
        setStingerDone(false);
      },
    });

    tl.to(bars, {
      scaleY: 1,
      duration: 0.32,
      stagger: 0.06,
      ease: "power4.in",
    }).to(bars, {
      scaleY: 0,
      transformOrigin: "bottom center",
      duration: 0.38,
      stagger: 0.08,
      ease: "power4.out",
      delay: 0.04,
    });
  }, []);

  return (
    <>
      {/* ── Stinger bars (portal-level, fixed) ── */}
      <StingerBars
        stingerRef1={stinger1}
        stingerRef2={stinger2}
        stingerRef3={stinger3}
      />

      {/* ── Yearbook Viewport overlay ── */}
      {viewportOpen && stingerDone && (
        <YearbookViewport onClose={closeViewport} />
      )}

      {/* ════════════════════════════════════════════
          YearbookSection — teaser/CTA background
      ════════════════════════════════════════════ */}
      <section
        ref={sectionRef}
        id="yearbook"
        aria-label="Yearbook Section"
        className="relative w-full overflow-hidden"
        style={{ minHeight: "70vh" }}
      >
        {/* Background photo */}
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={getAssetPath("/Memories/IMG_20251121_103356.jpg")}
          alt="Team Lykaions Batch 2026"
          className="absolute inset-0 w-full h-full object-cover"
          style={{ filter: "brightness(0.40) saturate(0.6)" }}
        />

        {/* Violet tint overlay */}
        <div
          className="absolute inset-0 z-[1] pointer-events-none"
          style={{
            background:
              "linear-gradient(120deg, rgba(66,0,153,0.60) 0%, rgba(110,0,255,0.20) 50%, transparent 100%)",
          }}
        />

        {/* Dot grid overlay */}
        <div
          className="absolute inset-0 z-[2] pointer-events-none"
          style={{
            backgroundImage:
              "radial-gradient(circle, rgba(255,255,255,0.20) 1px, transparent 1px)",
            backgroundSize: "22px 22px",
            opacity: 0.5,
          }}
        />

        {/* Dark vignette edges */}
        <div
          className="absolute inset-0 z-[3] pointer-events-none"
          style={{
            background:
              "radial-gradient(ellipse 100% 100% at 50% 50%, transparent 30%, rgba(0,0,0,0.85) 100%)",
          }}
        />

        {/* Main Content */}
        <div
          className="relative z-10 flex flex-col lg:flex-row items-end justify-between h-full w-full px-6 md:px-12 lg:px-20 py-20 gap-8"
          style={{ minHeight: "70vh" }}
        >
          {/* Left: Typography */}
          <div ref={textRef} className="flex flex-col gap-1">
            <p className="font-trap text-[10px] font-semibold uppercase tracking-[0.45em] text-white/60 mb-2">
              Relentless Pantheras · BSEMC
            </p>
            <h2
              className="font-formula uppercase leading-[0.88] text-white"
              style={{
                fontSize: "clamp(3rem, 8vw, 8rem)",
                textShadow: "0 0 60px rgba(110,0,255,0.45)",
              }}
            >
              <span className="block">TEAM</span>
              <span className="block text-[#6E00FF]">LYKAIONS</span>
              <span className="block">BATCH 2026</span>
            </h2>
          </div>

          {/* Right: CTA */}
          <div ref={ctaRef} className="flex-shrink-0">
            <button
              ref={btnRef}
              id="open-yearbook-btn"
              onClick={openViewport}
              className="group flex items-center gap-4 px-8 py-4 rounded text-white transition-all duration-300 cursor-pointer"
              aria-label="Open full yearbook viewer"
              style={{
                background:
                  "linear-gradient(135deg, rgba(110,0,255,0.85) 0%, rgba(66,0,153,0.9) 100%)",
                border: "1px solid rgba(110,0,255,0.5)",
                letterSpacing: "0.25em",
              }}
            >
              {/* Book icon */}
              <svg
                width="18"
                height="18"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                className="flex-shrink-0 group-hover:scale-110 transition-transform duration-300"
                aria-hidden="true"
              >
                <path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20" />
                <path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z" />
              </svg>
              <span className="font-formula text-sm uppercase tracking-[0.3em] group-hover:tracking-[0.4em] transition-all duration-300">
                VIEW YEARBOOK
              </span>
              {/* Arrow */}
              <svg
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                className="opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0 transition-all duration-300"
                aria-hidden="true"
              >
                <path d="M5 12h14M12 5l7 7-7 7" />
              </svg>
            </button>
          </div>
        </div>
      </section>
    </>
  );
}
