/* ─────────────────────────────────────────────────────────────
   SUB-COMPONENT: Student Card
───────────────────────────────────────────────────────────── */
function StudentCard({ student, delay }: { student: Student; delay: number }) {
  return (
    <div
      className="yearbook-card"
      style={{ animationDelay: `${delay}ms` }}
    >
      <div className="yearbook-card__photo">
        {student.photo ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={student.photo} alt={`${student.firstName} ${student.lastName}`} />
        ) : (
          <div className="yearbook-card__silhouette">{SILHOUETTE_SVG}</div>
        )}
        <div className="yearbook-card__badge">
          <span className="yearbook-card__badge-first">{student.firstName}</span>
          <span className="yearbook-card__badge-last">{student.lastName}</span>
        </div>
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   MAIN EXPORT: Yearbook Viewport
───────────────────────────────────────────────────────────── */
interface YearbookViewportProps {
  onClose: () => void;
}

export default function YearbookViewport({ onClose }: YearbookViewportProps) {
  const overlayRef = useRef<HTMLDivElement>(null);
  const panelRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  /* ── Mount animation: slide-up panel ── */
  useEffect(() => {
    const overlay = overlayRef.current;
    const panel = panelRef.current;
    if (!overlay || !panel) return;

    // Start hidden below viewport
    gsap.set(panel, { y: "100%", opacity: 0 });
    gsap.set(overlay, { opacity: 0 });

    const tl = gsap.timeline();
    tl.to(overlay, { opacity: 1, duration: 0.3, ease: "power2.out" })
      .to(panel, { y: "0%", opacity: 1, duration: 0.65, ease: "power4.out" }, "-=0.1");

    // Lock body scroll
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = "";
    };
  }, []);

  /* ── Close handler: animate out then call onClose ── */
  const handleClose = useCallback(() => {
    const overlay = overlayRef.current;
    const panel = panelRef.current;
    if (!overlay || !panel) { onClose(); return; }

    const tl = gsap.timeline({ onComplete: onClose });
    tl.to(panel, { y: "100%", opacity: 0, duration: 0.5, ease: "power4.in" })
      .to(overlay, { opacity: 0, duration: 0.25, ease: "power2.in" }, "-=0.2");
  }, [onClose]);

  /* ── Return to top of viewport content ── */
  const handleReturn = useCallback(() => {
    contentRef.current?.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  /* ── Keyboard: Escape closes ── */
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") handleClose();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [handleClose]);

  return (
    <div
      ref={overlayRef}
      className="yearbook-viewport-overlay"
      role="dialog"
      aria-modal="true"
      aria-label="Yearbook Full View"
    >
      {/* ── Slide-up panel ── */}
      <div ref={panelRef} className="yearbook-viewport-panel">

        {/* ══════════════════════════════════════════
            STICKY HEADER
        ══════════════════════════════════════════ */}
        <header className="yearbook-viewport-header">
          {/* Brand */}
          <div className="yearbook-viewport-brand">
            {/* Panther icon */}
            <svg
              className="yearbook-logo-panther"
              viewBox="0 0 64 64"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              aria-hidden="true"
            >
              <circle cx="32" cy="32" r="30" fill="#1a003a" stroke="#6E00FF" strokeWidth="1.5" />
              {/* simple panther silhouette */}
              <path
                d="M20 46 C18 38 16 30 22 24 C26 20 30 18 32 18 C34 18 38 20 42 24 C48 30 46 38 44 46"
                stroke="#6E00FF" strokeWidth="2" fill="none"
              />
              <circle cx="26" cy="27" r="2.5" fill="#6E00FF" />
              <circle cx="38" cy="27" r="2.5" fill="#6E00FF" />
              <path d="M28 34 Q32 37 36 34" stroke="#6E00FF" strokeWidth="1.5" fill="none" strokeLinecap="round" />
              <path d="M18 22 L24 26 M46 22 L40 26" stroke="#6E00FF" strokeWidth="1.5" strokeLinecap="round" />
            </svg>

            {/* Wolf / Lykaion icon */}
            <svg
              className="yearbook-logo-wolf"
              viewBox="0 0 64 64"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              aria-hidden="true"
            >
              <circle cx="32" cy="32" r="30" fill="#0d001f" stroke="#9B4DFF" strokeWidth="1.5" />
              {/* Wolf head silhouette */}
              <path
                d="M16 20 L20 30 L16 36 L24 32 L32 42 L40 32 L48 36 L44 30 L48 20 L40 24 L32 18 L24 24 Z"
                fill="none" stroke="#9B4DFF" strokeWidth="1.5" strokeLinejoin="round"
              />
              <circle cx="26" cy="28" r="2" fill="#9B4DFF" />
              <circle cx="38" cy="28" r="2" fill="#9B4DFF" />
            </svg>

            {/* Title */}
            <div className="yearbook-viewport-title">
              <span className="yearbook-viewport-subtitle">Relentless Pantheras · BSEMC</span>
              <span className="yearbook-viewport-main-title">Team Lykaions</span>
            </div>
          </div>

          {/* Action buttons */}
          <div className="yearbook-viewport-actions">
            <button
              id="yearbook-return-btn"
              className="yearbook-btn yearbook-btn--return"
              onClick={handleReturn}
              title="Return to top"
              aria-label="Return to top of yearbook"
            >
              {/* Up-arrow icon */}
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <path d="M12 19V5M5 12l7-7 7 7" />
              </svg>
              <span>Return</span>
            </button>

            <button
              id="yearbook-close-btn"
              className="yearbook-btn yearbook-btn--close"
              onClick={handleClose}
              title="Close yearbook"
              aria-label="Close yearbook viewer"
            >
              {/* X icon */}
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </header>

        {/* ══════════════════════════════════════════
            SCROLLABLE CONTENT
        ══════════════════════════════════════════ */}
        <div ref={contentRef} className="yearbook-viewport-content">

          {/* ── Hero Banner ── */}
          <div className="yearbook-hero-banner">
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={getAssetPath("/Memories/IMG_20251121_103356.jpg")}
              alt="Team Lykaions hero"
              style={{
                position: "absolute", inset: 0, width: "100%", height: "100%",
                objectFit: "cover", objectPosition: "center top",
                filter: "brightness(0.25) saturate(0.5)",
              }}
            />
            <div className="yearbook-hero-banner__overlay" />
            <div className="yearbook-hero-banner__dots" />
            <div className="yearbook-hero-banner__text">
              <p className="yearbook-hero-banner__sub">Relentless Pantheras · BSEMC</p>
              <h1 className="yearbook-hero-banner__title">
                TEAM<br />
                <span style={{ color: "#6E00FF" }}>LYKAIONS</span>
              </h1>
            </div>
          </div>

          {/* ── SECTION: Young Nobles ── */}
          <div className="yearbook-section-block">
            <h2 className="yearbook-section-heading">Young Nobles of BSEMC 2026</h2>
            <div className="yearbook-grid yearbook-grid--nobles">
              {YOUNG_NOBLES.map((s, i) => (
                <StudentCard key={i} student={s} delay={i * 40} />
              ))}
            </div>
          </div>

          {/* ── SECTION: OG and UNC ── */}
          <div className="yearbook-section-block yearbook-section-block--secondary">
            <h2 className="yearbook-section-heading">OG and UNC of BSEMC 2026</h2>
            <div className="yearbook-grid yearbook-grid--og">
              {OG_AND_UNC.map((s, i) => (
                <StudentCard key={i} student={s} delay={i * 60} />
              ))}
            </div>
          </div>

          {/* ── Footer inside viewport ── */}
          <div className="yearbook-viewport-footer">
            <button
              className="yearbook-btn yearbook-btn--return yearbook-btn--large"
              onClick={handleClose}
              aria-label="Close yearbook and return to site"
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
              Close Yearbook
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
